1	'use strict';
2	// 프로젝트(저장소) 레지스트리 + "최초 1회" 디스크 스캔 (T1).
3	//
4	// 설계 원칙(사용자 결정): 디스크 스캔은 최초 1회(또는 사용자가 명시적으로 재스캔을
5	// 눌렀을 때)만 실행한다. 평소에는 projects.json에 저장된 목록(list)만 쓴다.
6	// 자동/백그라운드 스캔은 없다.
7	//
8	// ★ 보안 가드:
9	//  - scan()은 디렉토리 "이름/존재"만 본다. 어떤 파일의 내용도 읽지 않는다
10	//    (readdir/stat 계열만 사용 — fs.readFile 금지).
11	//  - 심볼릭 링크는 따라가지 않는다(무한 루프 방지).
12	//  - 모델 홈 자체(~/.claude·~/.codex·~/.agents 등)는 프로젝트가 아니므로 후보 제외.
13	//    (~/.gemini는 지원 중단 후에도 방어적으로 제외 목록에 유지.)
14	//  - EXCLUDE_DIRS와 숨김 디렉토리('.'로 시작)에는 하위 진입하지 않는다
15	//    (마커 존재 확인용 stat은 허용).
16	
17	const fs = require('fs');
18	const os = require('os');
19	const path = require('path');
20	const paths = require('./paths');
21	
22	// 프로젝트로 인정하는 마커 — 존재만 확인 (0번 검증 문서의 모델별 프로젝트 위치 기준)
23	// gemini 지원 중단(D31)으로 GEMINI.md/.gemini 마커 제거 — 2모델 체제.
24	const MARKERS = ['.claude', 'CLAUDE.md', 'AGENTS.md', '.agents', '.codex'];
25	
26	// 하위 진입 금지 디렉토리 (성능·안전 — 진입만 금지, 마커 stat은 별개)
27	const EXCLUDE_DIRS = [
28	  'node_modules', '.git', 'Library', '.Trash', '.cache', '.npm', '.nvm',
29	  '.vscode', '.cursor', 'Applications', 'Music', 'Movies', 'Pictures',
30	];
31	
32	// 도구 홈 절대 경로 집합 — 스캔 후보에서 제외할 대상
33	function toolHomeSet() {
34	  const h = os.homedir();
35	  return new Set([
36	    path.join(h, '.claude'),
37	    path.join(h, '.codex'),
38	    path.join(h, '.gemini'),
39	    path.join(h, '.agents'),
40	  ]);
41	}
42	
43	// 폴더에 존재하는 마커 목록. lstat으로 "존재"만 확인한다(내용 안 읽음).
44	function markersOf(dir) {
45	  const found = [];
46	  for (const m of MARKERS) {
47	    try {
48	      fs.lstatSync(path.join(dir, m));
49	      found.push(m);
50	    } catch {
51	      // 없음 — 통과
52	    }
53	  }
54	  return found;
55	}
56	
57	// rootDir부터 트리를 내려가며 MARKERS 중 하나라도 있는 폴더를 후보로 수집한다.
58	//  - 후보 발견 시 그 폴더 하위로는 더 내려가지 않는다(중첩 프로젝트는 1차 범위 밖).
59	//  - 홈 디렉토리 자체는 후보로 삼지 않는다(홈의 .claude 등은 프로젝트 마커가 아니라
60	//    글로벌 도구 홈이므로) — 하위 탐색은 계속한다.
61	//  - 반환: [{ root, markers: [...] }]
62	function scan(rootDir, { maxDepth = 4 } = {}) {
63	  const found = [];
64	  const toolHomes = toolHomeSet();
65	  const home = os.homedir();
66	
67	  function walk(dir, depth) {
68	    if (toolHomes.has(dir)) return; // 도구 홈 자체는 프로젝트가 아님
69	    let st;
70	    try {
71	      st = fs.lstatSync(dir);
72	    } catch {
73	      return; // 접근 불가/없음 — 조용히 건너뜀
74	    }
75	    if (st.isSymbolicLink() || !st.isDirectory()) return;
76	
77	    if (dir !== home) {
78	      const markers = markersOf(dir);
79	      if (markers.length > 0) {
80	        found.push({ root: dir, markers });
81	        return; // 후보 발견 — 하위 진입 중단
82	      }
83	    }
84	
85	    if (depth >= maxDepth) return;
86	    let entries;
87	    try {
88	      entries = fs.readdirSync(dir, { withFileTypes: true });
89	    } catch {
90	      return; // 권한 없음 등 — 조용히 건너뜀
91	    }
92	    for (const e of entries) {
93	      if (!e.isDirectory() || e.isSymbolicLink()) continue; // 심볼릭 링크 안 따라감
94	      if (e.name.startsWith('.') || EXCLUDE_DIRS.includes(e.name)) continue; // 진입 금지
95	      walk(path.join(dir, e.name), depth + 1);
96	    }
97	  }
98	
99	  walk(path.resolve(rootDir), 0);
100	  return found;
101	}
102	
103	// projects.json 읽기. 없거나 깨졌으면 기본값 {version:1, projects:[]}.
104	function load() {
105	  const file = paths.projectsFile();
106	  if (!fs.existsSync(file)) return { version: 1, projects: [] };
107	  try {
108	    const data = JSON.parse(fs.readFileSync(file, 'utf8'));
109	    if (!data || !Array.isArray(data.projects)) return { version: 1, projects: [] };
110	    return { version: data.version || 1, projects: data.projects };
111	  } catch {
112	    return { version: 1, projects: [] };
113	  }
114	}
115	
116	// projects.json 쓰기 (paths.projectsFile 위치 — 모드별 canonical에 자동 격리).
117	// 레지스트리 객체({version, projects}) 또는 프로젝트 배열 둘 다 받는다.
118	function save(reg) {
119	  const data = Array.isArray(reg) ? { version: 1, projects: reg } : reg;
120	  const file = paths.projectsFile();
121	  fs.mkdirSync(path.dirname(file), { recursive: true });
122	  fs.writeFileSync(file, JSON.stringify(data, null, 2) + '\n', 'utf8');
123	  return file;
124	}
125	
126	// 수동 등록: 존재하는 디렉토리 + 마커 1개 이상 확인, 중복(root)이면 무시.
127	function add(root) {
128	  const abs = path.resolve(root);
129	  let st;
130	  try {
131	    st = fs.statSync(abs);
132	  } catch {
133	    throw new Error('경로가 존재하지 않습니다: ' + abs);
134	  }
135	  if (!st.isDirectory()) throw new Error('디렉토리가 아닙니다: ' + abs);
136	  const markers = markersOf(abs);
137	  if (markers.length === 0) {
138	    throw new Error('프로젝트 마커(' + MARKERS.join('/') + ')가 없습니다: ' + abs);
139	  }
140	  const reg = load();
141	  if (reg.projects.some((p) => p.root === abs)) {
142	    return { added: false, reason: 'duplicate', root: abs };
143	  }
144	  const entry = { root: abs, markers, added_at: new Date().toISOString(), source: 'manual' };
145	  reg.projects.push(entry);
146	  save(reg);
147	  return { added: true, project: entry };
148	}
149	
150	// 등록 해제 (root 절대경로 기준).
151	function remove(root) {
152	  const abs = path.resolve(root);
153	  const reg = load();
154	  const before = reg.projects.length;
155	  reg.projects = reg.projects.filter((p) => p.root !== abs);
156	  if (reg.projects.length === before) return { removed: false, root: abs };
157	  save(reg);
158	  return { removed: true, root: abs };
159	}
160	
161	// 등록된 프로젝트 배열.
162	function list() {
163	  return load().projects;
164	}
165	
166	// scan() 결과를 레지스트리에 병합. 이미 등록된 root는 건너뛴다(source:'scan').
167	function adoptScan(candidates) {
168	  const reg = load();
169	  const known = new Set(reg.projects.map((p) => p.root));
170	  const adopted = [];
171	  for (const c of candidates || []) {
172	    if (!c || !c.root || known.has(c.root)) continue;
173	    const entry = {
174	      root: c.root,
175	      markers: Array.isArray(c.markers) ? c.markers : [],
176	      added_at: new Date().toISOString(),
177	      source: 'scan',
178	    };
179	    reg.projects.push(entry);
180	    known.add(c.root);
181	    adopted.push(entry);
182	  }
183	  if (adopted.length > 0) save(reg);
184	  return { adopted: adopted.length, total: reg.projects.length };
185	}
186	
187	module.exports = { MARKERS, EXCLUDE_DIRS, scan, load, save, add, remove, list, adoptScan };
188

1	'use strict';
2	// 보안 가드레일 한 곳 모음 (security-check.md와 동기화).
3	//  - 거부목록: 시크릿/개인정보 파일은 절대 읽지/수집하지 않는다.
4	//  - PI 게이트: 읽은 본문에서 개인정보·시크릿 의심 패턴을 찾아 사용자 확인을 요구한다.
5	
6	// (1) 거부목록 — 파일 경로가 하나라도 매칭되면 읽기 거부
7	const DENY_PATTERNS = [
8	  /auth\.json$/i,
9	  /oauth_creds\.json$/i,
10	  /google_account/i,
11	  /\.sqlite(-shm|-wal)?$/i,
12	  /(^|\/)(sessions|archived_sessions)\//i,
13	  /history\.jsonl$/i,
14	  /\.env$/i,
15	  /\.(key|pem)$/i,
16	];
17	
18	function isDenied(filePath) {
19	  return DENY_PATTERNS.some((re) => re.test(filePath));
20	}
21	
22	// (2) 개인정보/시크릿 의심 패턴 — 본문에서 탐지
23	const PI_PATTERNS = [
24	  { name: '이메일', re: /[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/gi },
25	  { name: '토큰/키 키워드', re: /\b(token|secret|password|api[_-]?key)\b/gi },
26	  { name: '주민번호 형태', re: /\b\d{6}-\d{7}\b/g },
27	  { name: '전화번호 형태', re: /\b01\d-?\d{3,4}-?\d{4}\b/g },
28	];
29	
30	// 본문에서 감지된 패턴 이름 목록 반환 (없으면 빈 배열)
31	function detectPI(text) {
32	  const found = [];
33	  for (const p of PI_PATTERNS) {
34	    if (new RegExp(p.re.source, p.re.flags).test(text)) found.push(p.name);
35	  }
36	  return found;
37	}
38	
39	// 감지된 부분을 가린(마스킹) 텍스트 반환
40	function mask(text) {
41	  let out = text;
42	  for (const p of PI_PATTERNS) {
43	    out = out.replace(new RegExp(p.re.source, p.re.flags), '****');
44	  }
45	  return out;
46	}
47	
48	// PI를 포함하는 줄만 골라 마스킹해서 보여주기 (확인 모달/CLI 경고용)
49	function maskedSensitiveLines(text) {
50	  return text
51	    .split('\n')
52	    .filter((line) => detectPI(line).length > 0)
53	    .map((line) => mask(line));
54	}
55	
56	module.exports = { isDenied, detectPI, mask, maskedSensitiveLines };
57

1	'use strict';
2	// 하이브리드 스캐너 (D9):
3	//  - discover(): 어떤 항목이 있는지(존재/경로)만 본다. 내용은 읽지 않는다.
4	//  - readItemContent(): 사용자가 고른 항목의 내용만 읽고, PI를 함께 탐지한다.
5	
6	const fs = require('fs');
7	const path = require('path');
8	const paths = require('./paths');
9	const security = require('./security');
10	const projects = require('./projects');
11	
12	// 지시문 트랙: 세 도구의 글로벌 지시문이 존재하는지만 발견 (내용 안 읽음)
13	function discoverInstructions() {
14	  return paths.TOOLS.map((tool) => {
15	    const filePath = paths.instructionPath(tool);
16	    return {
17	      id: 'instr-global',
18	      type: 'instruction',
19	      scope: 'global',
20	      tool,
21	      name: paths.INSTRUCTION_FILENAME[tool],
22	      path: filePath,
23	      exists: fs.existsSync(filePath),
24	    };
25	  });
26	}
27	
28	// 프로젝트 지시문 발견(T2): 등록된 프로젝트별 지시문 파일의 "존재 여부만" 본다 (내용 안 읽음).
29	//  - Claude는 후보가 2곳(./CLAUDE.md, ./.claude/CLAUDE.md)이라 후보마다 한 항목씩 낸다.
30	//  - pull/push는 이번 범위 밖 — 순수 표시용.
31	function discoverProjectInstructions() {
32	  const items = [];
33	  for (const proj of projects.list()) {
34	    const candidates = paths.projectInstructionPaths(proj.root);
35	    for (const tool of paths.TOOLS) {
36	      for (const filePath of candidates[tool] || []) {
37	        items.push({
38	          id: 'instr-project',
39	          type: 'instruction',
40	          scope: 'project',
41	          projectRoot: proj.root,
42	          tool,
43	          name: path.relative(proj.root, filePath), // 예: 'CLAUDE.md' / '.claude/CLAUDE.md'
44	          path: filePath,
45	          exists: fs.existsSync(filePath),
46	        });
47	      }
48	    }
49	  }
50	  return items;
51	}
52	
53	// agent 트랙 하이브리드 발견: 도구별 agent 폴더에서 "파일명"만 본다 (내용 안 읽음).
54	//  - Claude = .md, Codex = .toml 만 정식 agent로 인정.
55	//  - 확장자가 안 맞는 파일(README, Codex 폴더의 .md 등)은 nonStandard로 분리(스킵 대상).
56	//  - T2: 글로벌(도구 홈) + 등록된 프로젝트의 agent 폴더를 같은 규칙으로 합류.
57	function discoverAgents() {
58	  const agents = [];
59	  const nonStandard = [];
60	
61	  // 한 agent 폴더를 훑는 공통 루틴 (extra = scope/projectRoot 등 부가 필드)
62	  function scanDir(tool, dir, extra) {
63	    const ext = paths.agentExt(tool);
64	    if (!fs.existsSync(dir)) return;
65	    for (const file of fs.readdirSync(dir)) {
66	      const full = path.join(dir, file);
67	      if (!fs.statSync(full).isFile()) continue;
68	      if (file.toLowerCase() === 'readme.md') continue;
69	      if (file.endsWith(ext)) {
70	        agents.push({ tool, name: file.slice(0, -ext.length), path: full, exists: true, ...extra });
71	      } else {
72	        nonStandard.push({ tool, file, path: full, reason: `${tool} agent는 ${ext}만 인정`, ...extra });
73	      }
74	    }
75	  }
76	
77	  // 글로벌: 기존 그대로 (scope만 명시)
78	  for (const tool of paths.TOOLS) {
79	    scanDir(tool, paths.agentDir(tool), { scope: 'global' });
80	  }
81	  // 프로젝트: 등록된 프로젝트만 (같은 확장자 규칙 — codex는 .toml)
82	  for (const proj of projects.list()) {
83	    for (const tool of paths.TOOLS) {
84	      scanDir(tool, paths.projectAgentDir(proj.root, tool), { scope: 'project', projectRoot: proj.root });
85	    }
86	  }
87	  return { agents, nonStandard };
88	}
89	
90	// skill 하이브리드 발견: 소스 디렉토리에서 "<name>/SKILL.md" 폴더만 찾는다(내용 안 읽음).
91	//  - 비공식 소스(official:false)의 skill은 official:false로 표시해 사용자에게 알린다(D11).
92	//  - 플러그인 소스는 재귀 탐색(깊이 제한). 거부목록 경로는 건너뛴다.
93	//  - T2: 글로벌 소스 뒤에 등록된 프로젝트의 소스(projectSkillSources)를 합류.
94	//    글로벌이 앞이므로 이름이 겹칠 때 기본 매칭(첫 항목)은 기존과 동일하게 글로벌이다.
95	function discoverSkills() {
96	  const skills = [];
97	  const sources = [
98	    ...paths.skillSources(), // 글로벌 (scope 미지정 → 'global'로 명시)
99	    ...projects.list().flatMap((p) => paths.projectSkillSources(p.root)), // scope:'project'+projectRoot 포함
100	  ];
101	  for (const src of sources) {
102	    for (const folder of findSkillFolders(src.dir, src.recursive)) {
103	      skills.push({
104	        id: 'skill-' + folder.name,
105	        type: 'skill',
106	        name: folder.name,
107	        tool: src.tool,
108	        source_id: src.id,
109	        official: src.official,
110	        shared: !!src.shared,
111	        plugin: !!src.plugin,
112	        scope: src.scope || 'global',
113	        ...(src.projectRoot ? { projectRoot: src.projectRoot } : {}),
114	        path: folder.skillMdPath,
115	        exists: true,
116	      });
117	    }
118	  }
119	  return skills;
120	}
121	
122	// 디렉토리에서 SKILL.md를 가진 폴더를 찾는다. recursive면 깊이 제한 walk.
123	function findSkillFolders(dir, recursive, depth = 0) {
124	  if (!fs.existsSync(dir) || depth > 6) return [];
125	  const out = [];
126	  let entries = [];
127	  try {
128	    entries = fs.readdirSync(dir, { withFileTypes: true });
129	  } catch {
130	    return out;
131	  }
132	  for (const e of entries) {
133	    if (!e.isDirectory()) continue;
134	    const folder = path.join(dir, e.name);
135	    if (security.isDenied(folder) || e.name === 'node_modules' || e.name === '.git') continue;
136	    const skillMd = path.join(folder, 'SKILL.md');
137	    if (fs.existsSync(skillMd)) {
138	      out.push({ name: e.name, skillMdPath: skillMd, folder });
139	    } else if (recursive) {
140	      out.push(...findSkillFolders(folder, true, depth + 1));
141	    }
142	  }
143	  return out;
144	}
145	
146	// 특정 항목의 내용을 읽는다 (사용자가 클릭/지정한 경우에만 호출).
147	//  - 거부목록 경로는 읽지 않는다.
148	//  - 본문에서 PI를 탐지해 함께 반환한다.
149	function readItemContent(item) {
150	  if (security.isDenied(item.path)) {
151	    throw new Error(`거부목록에 해당하는 경로라 읽지 않습니다: ${item.path}`);
152	  }
153	  if (!fs.existsSync(item.path)) {
154	    throw new Error(`파일이 없습니다: ${item.path}`);
155	  }
156	  const text = fs.readFileSync(item.path, 'utf8');
157	  return { text, pi: security.detectPI(text) };
158	}
159	
160	module.exports = {
161	  discoverInstructions,
162	  discoverProjectInstructions,
163	  discoverAgents,
164	  discoverSkills,
165	  readItemContent,
166	};
167

1	'use strict';
2	// 두 도구(claude·codex)의 설정 홈 경로와 동기화 대상 위치를 정의한다.
3	// (과거 gemini도 지원했으나 사용자 결정으로 전면 제거 — 2모델 체제.)
4	// 모드(mode.js)에 따라 읽는 곳이 갈린다:
5	//  - dummy : 프로젝트 안 fixtures/ (실제 파일 안 건드림)
