1079	//  - syncState는 instrMatrix()의 판정을 재사용(중복 구현 금지).
1080	//  - 개별 읽기 실패(PI 제외)는 해당 모델 readError로 담고 throw하지 않는다(D26 우아한 실패).
1081	//  - sideBySide: 두 모델 본문이 모두 있고 서로 다를 때만 diff.sideBySide, 아니면 null.
1082	// 반환: { syncState, models:{ [tool]:{exists,path,body,readError?} }, sideBySide|null }
1083	function instrContent({ piAck } = {}) {
1084	  const syncState = instrMatrix().syncState; // 판정 재사용(3파일 해시 그룹 기반)
1085	  const discovered = scanner.discoverInstructions(); // {tool, path, exists}[]
1086	  const models = {};
1087	  for (const tool of paths.TOOLS) {
1088	    const item = discovered.find((i) => i.tool === tool);
1089	    const filePath = item ? item.path : paths.instructionPath(tool);
1090	    if (!item || !item.exists) {
1091	      models[tool] = { exists: false, path: filePath, body: null };
1092	      continue;
1093	    }
1094	    try {
1095	      let { text, pi } = scanner.readItemContent({ path: filePath });
1096	      if (pi.length > 0) {
1097	        // PI 게이트는 pull/item-content와 동일하게 전파(서버 409). piAck로 마스킹/진행 처리.
1098	        if (!piAck) throw new PiGateError(pi, security.maskedSensitiveLines(text));
1099	        if (piAck === 'mask') text = security.mask(text);
1100	        // 'proceed' → 원문 그대로
1101	      }
1102	      models[tool] = { exists: true, path: filePath, body: text };
1103	    } catch (e) {
1104	      if (e instanceof PiGateError) throw e; // PI는 그대로 전파(우아한 실패 대상 아님)
1105	      models[tool] = { exists: false, path: filePath, body: null, readError: e.message };
1106	    }
1107	  }
1108	
1109	  const claudeBody = models.claude && models.claude.exists ? models.claude.body : null;
1110	  const codexBody = models.codex && models.codex.exists ? models.codex.body : null;
1111	  const sideBySide =
1112	    claudeBody != null && codexBody != null && claudeBody !== codexBody
1113	      ? diff.sideBySide(claudeBody, codexBody)
1114	      : null;
1115	
1116	  return { syncState, models, sideBySide };
1117	}
