1119	// (2) instrSync — 기준 모델로 한 방 동기화.
1120	//  - base = 'claude'|'codex'.
1121	//  - apply:false(기본): 실제 쓰기 없이 모델별 diff 요약(변경 라인 수·생성될 파일 여부)만 반환.
1122	//      · 쓰기 없음 검증을 위해 canonical에도 쓰지 않는다 — 기준 파일 본문을 직접 읽어
1123	//        transformInstr.render + diff.lineDiff로 대상별 미리보기를 만든다(디스크 무변경).
1124	//  - apply:true: 기존 pull({from:base}) → push({to,apply:true}) 파이프라인을 그대로 재사용
1125	//      (자동 백업·synclog·PI 게이트·gitCommit 상속). 새 쓰기 경로는 만들지 않는다.
1126	//      PI 게이트는 pull이 PiGateError를 던지며 여기서 잡지 않고 그대로 전파(서버 409).
1127	function instrSync({ base, apply, piAck }) {
1128	  if (!paths.TOOLS.includes(base)) {
1129	    throw new Error("기준 모델(base)이 올바르지 않습니다: " + base + " ('claude'|'codex')");
1130	  }
1131	  const baseItem = scanner.discoverInstructions().find((i) => i.tool === base);
1132	  if (!baseItem || !baseItem.exists) {
1133	    throw new Error(`기준 모델(${base})의 지시문 파일이 없습니다: ${baseItem ? baseItem.path : base}`);
1134	  }
1135	
1136	  if (!apply) {
1137	    // 미리보기: 디스크 무변경. 기준 파일 본문을 읽어 대상 모델별 diff 요약만 만든다.
1138	    const { text: baseBody } = scanner.readItemContent({ path: baseItem.path });
1139	    const targets = paths.TOOLS.filter((t) => t !== base).map((to) => {
1140	      const rendered = transformInstr.render(baseBody, to); // 지시문은 본문 변환 없음(파일명만)
1141	      const exists = fs.existsSync(rendered.targetPath);
1142	      const deployed = exists ? fs.readFileSync(rendered.targetPath, 'utf8') : '';
1143	      const d = diff.lineDiff(deployed, rendered.body);
1144	      const added = d.filter((x) => x.type === '+').length;
1145	      const removed = d.filter((x) => x.type === '-').length;
1146	      return {
1147	        to,
1148	        targetPath: rendered.targetPath,
1149	        exists,
1150	        willCreate: !exists,     // 대상 파일이 없으면 새로 생성됨
1151	        hasChanges: diff.hasChanges(d),
1152	        added,                   // 추가될 라인 수
1153	        removed,                 // 사라질 라인 수
1154	        changedLines: added + removed,
1155	      };
1156	    });
1157	    return { applied: false, base, targets };
1158	  }
1159	
1160	  // 적용: 기존 파이프라인 재사용. pull(base→canonical) 후 나머지 모델로 push(apply:true).
1161	  const pulled = pull({ from: base, piAck }); // PI 게이트 시 PiGateError 전파
1162	  if (!pulled.imported) {
1163	    // PI 게이트에서 사용자가 제외를 선택 → 기준을 canonical에 넣지 않아 동기화 중단.
1164	    return { applied: true, base, pulled: { imported: false, reason: pulled.reason }, results: [] };
1165	  }
1166	  const results = [];
1167	  for (const to of paths.TOOLS) {
1168	    if (to === base) continue;
1169	    try {
1170	      const r = push({ to, apply: true }); // 자동 백업·synclog·gitCommit 상속
1171	      results.push({ to, applied: true, targetPath: r.targetPath, backupPath: r.backupPath || null });
1172	    } catch (e) {
1173	      // 부분 실패: 중단하지 말고 모델별 결과로 기록.
1174	      results.push({ to, applied: false, error: e.message });
1175	    }
1176	  }
1177	  return {
1178	    applied: true,
1179	    base,
1180	    pulled: { imported: true, source_tool: pulled.meta.source_tool, piHandled: pulled.piHandled },
1181	    results,
1182	  };
1183	}
