20	function sendFile(res, file, type) {
21	  fs.readFile(file, (err, data) => {
22	    if (err) {
23	      res.writeHead(404);
24	      res.end('not found');
25	      return;
26	    }
27	    res.writeHead(200, { 'Content-Type': type });
28	    res.end(data);
29	  });
